        /* radix-5 n2=0 [fwd] */
        {
        __m512d s1r=_mm512_add_pd(a_x1_re,a_x4_re), s1i=_mm512_add_pd(a_x1_im,a_x4_im);
        __m512d s2r=_mm512_add_pd(a_x2_re,a_x3_re), s2i=_mm512_add_pd(a_x2_im,a_x3_im);
        __m512d d1r=_mm512_sub_pd(a_x1_re,a_x4_re), d1i=_mm512_sub_pd(a_x1_im,a_x4_im);
        __m512d d2r=_mm512_sub_pd(a_x2_re,a_x3_re), d2i=_mm512_sub_pd(a_x2_im,a_x3_im);
        __m512d ss_r=_mm512_add_pd(s1r,s2r), ss_i=_mm512_add_pd(s1i,s2i);
        __m512d t0r=_mm512_fnmadd_pd(cD,ss_r,a_x0_re), t0i=_mm512_fnmadd_pd(cD,ss_i,a_x0_im);
        a_x0_re=_mm512_add_pd(a_x0_re,ss_r); a_x0_im=_mm512_add_pd(a_x0_im,ss_i);
        __m512d p1r=_mm512_fmadd_pd(cA,_mm512_sub_pd(s1r,s2r),t0r), p1i=_mm512_fmadd_pd(cA,_mm512_sub_pd(s1i,s2i),t0i);
        __m512d p2r=_mm512_fnmadd_pd(cA,_mm512_sub_pd(s1r,s2r),t0r), p2i=_mm512_fnmadd_pd(cA,_mm512_sub_pd(s1i,s2i),t0i);
        __m512d qar=_mm512_fmadd_pd(cC,d2i,_mm512_mul_pd(cB,d1i)), qai=_mm512_fmadd_pd(cC,d2r,_mm512_mul_pd(cB,d1r));
        __m512d qbr=_mm512_fmsub_pd(cB,d2i,_mm512_mul_pd(cC,d1i)), qbi=_mm512_fmsub_pd(cB,d2r,_mm512_mul_pd(cC,d1r));
        a_x1_re=_mm512_add_pd(p1r,qar); a_x1_im=_mm512_sub_pd(p1i,qai);
        a_x4_re=_mm512_sub_pd(p1r,qar); a_x4_im=_mm512_add_pd(p1i,qai);
        a_x2_re=_mm512_sub_pd(p2r,qbr); a_x2_im=_mm512_add_pd(p2i,qbi);
        a_x3_re=_mm512_add_pd(p2r,qbr); a_x3_im=_mm512_sub_pd(p2i,qbi);
        }

        _mm512_store_pd(&a_spill_re[0*8], a_x0_re);
        _mm512_store_pd(&a_spill_im[0*8], a_x0_im);
        _mm512_store_pd(&a_spill_re[1*8], a_x1_re);
        _mm512_store_pd(&a_spill_im[1*8], a_x1_im);
        _mm512_store_pd(&a_spill_re[2*8], a_x2_re);
        _mm512_store_pd(&a_spill_im[2*8], a_x2_im);
        _mm512_store_pd(&a_spill_re[3*8], a_x3_re);
        _mm512_store_pd(&a_spill_im[3*8], a_x3_im);
        _mm512_store_pd(&a_spill_re[4*8], a_x4_re);
        _mm512_store_pd(&a_spill_im[4*8], a_x4_im);

        /* sub-FFT n2=1 */
        a_x0_re = LD(&rio_re[m+1*ios]);
        a_x0_im = LD(&rio_im[m+1*ios]);
        { __m512d a_tr = a_x0_re;
          a_x0_re = _mm512_fmsub_pd(a_x0_re,w1r,_mm512_mul_pd(a_x0_im,w1i));
          a_x0_im = _mm512_fmadd_pd(a_tr,w1i,_mm512_mul_pd(a_x0_im,w1r)); }
        a_x1_re = LD(&rio_re[m+3*ios]);
        a_x1_im = LD(&rio_im[m+3*ios]);
        { __m512d a_tr = a_x1_re;
          a_x1_re = _mm512_fmsub_pd(a_x1_re,w3r,_mm512_mul_pd(a_x1_im,w3i));
          a_x1_im = _mm512_fmadd_pd(a_tr,w3i,_mm512_mul_pd(a_x1_im,w3r)); }
        a_x2_re = LD(&rio_re[m+5*ios]);
        a_x2_im = LD(&rio_im[m+5*ios]);
        { __m512d a_tr = a_x2_re;
          a_x2_re = _mm512_fmsub_pd(a_x2_re,w5r,_mm512_mul_pd(a_x2_im,w5i));
          a_x2_im = _mm512_fmadd_pd(a_tr,w5i,_mm512_mul_pd(a_x2_im,w5r)); }
        a_x3_re = LD(&rio_re[m+7*ios]);
        a_x3_im = LD(&rio_im[m+7*ios]);
        { __m512d a_tr = a_x3_re;
          a_x3_re = _mm512_fmsub_pd(a_x3_re,w7r,_mm512_mul_pd(a_x3_im,w7i));
          a_x3_im = _mm512_fmadd_pd(a_tr,w7i,_mm512_mul_pd(a_x3_im,w7r)); }
        a_x4_re = LD(&rio_re[m+9*ios]);
        a_x4_im = LD(&rio_im[m+9*ios]);
        { __m512d a_tr = a_x4_re;
          a_x4_re = _mm512_fmsub_pd(a_x4_re,w9r,_mm512_mul_pd(a_x4_im,w9i));
          a_x4_im = _mm512_fmadd_pd(a_tr,w9i,_mm512_mul_pd(a_x4_im,w9r)); }

